<span class="line"><span style="color:#CBA6F7;">                let</span><span style="color:#CDD6F4;"> _</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> nix</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">sched</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">unshare</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">nix</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">sched</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">CloneFlags</span><span style="color:#94E2D5;">::</span><span style="color:#FAB387;">CLONE_NEWNET</span><span style="color:#9399B2;">);</span></span>
